#pragma once

#include <string>
#include <vector>

#include "envoy/http/filter.h"
#include "envoy/server/filter_config.h"

#include "source/common/common/logger.h"

namespace Envoy {
namespace Extensions {
namespace HttpFilters {
namespace CustomHeaderInjection {

/**
 * Configuration for a header injection rule.
 */
struct HeaderInjectionRule {
  std::string header_name;
  std::string header_value;
  bool inject_on_request{true};
  bool inject_on_response{false};
};

/**
 * Encapsulates the filter configuration.
 */
class Config : public Router::RouteSpecificFilterConfig,
               public Logger::Loggable<Logger::Id::config> {
public:
  Config() = default;
  virtual ~Config() = default;

  const std::vector<HeaderInjectionRule>& getRules() const { return rules_; }
  void addRule(const HeaderInjectionRule& rule) { rules_.push_back(rule); }

private:
  std::vector<HeaderInjectionRule> rules_;
};

using ConfigSharedPtr = std::shared_ptr<Config>;

/**
 * Custom header injection filter that injects headers into requests and responses.
 */
class CustomHeaderInjectionFilter : public Http::StreamFilter,
                                    public Logger::Loggable<Logger::Id::filter> {
public:
  CustomHeaderInjectionFilter(const ConfigSharedPtr config);
  ~CustomHeaderInjectionFilter() override;

  // Http::StreamFilterBase
  void onDestroy() override {}

  // StreamDecoderFilter
  Http::FilterHeadersStatus decodeHeaders(Http::RequestHeaderMap& headers, bool) override;
  Http::FilterDataStatus decodeData(Buffer::Instance&, bool) override {
    return Http::FilterDataStatus::Continue;
  }
  Http::FilterTrailersStatus decodeTrailers(Http::RequestTrailerMap&) override {
    return Http::FilterTrailersStatus::Continue;
  }
  void setDecoderFilterCallbacks(Http::StreamDecoderFilterCallbacks& callbacks) override;

  // StreamEncoderFilter
  Http::Filter1xxHeadersStatus encode1xxHeaders(Http::ResponseHeaderMap&) override {
    return Http::Filter1xxHeadersStatus::Continue;
  }
  Http::FilterHeadersStatus encodeHeaders(Http::ResponseHeaderMap& headers, bool) override;
  Http::FilterDataStatus encodeData(Buffer::Instance&, bool) override {
    return Http::FilterDataStatus::Continue;
  }
  Http::FilterTrailersStatus encodeTrailers(Http::ResponseTrailerMap&) override {
    return Http::FilterTrailersStatus::Continue;
  }
  Http::FilterMetadataStatus encodeMetadata(Http::MetadataMap&) override {
    return Http::FilterMetadataStatus::Continue;
  }
  void setEncoderFilterCallbacks(Http::StreamEncoderFilterCallbacks& callbacks) override;

private:
  const ConfigSharedPtr config_;
  Http::StreamDecoderFilterCallbacks* decoder_callbacks_{};
  Http::StreamEncoderFilterCallbacks* encoder_callbacks_{};
};

} // namespace CustomHeaderInjection
} // namespace HttpFilters
} // namespace Extensions
} // namespace Envoy

#include "source/extensions/filters/http/custom_header_injection/filter.h"

namespace Envoy {
namespace Extensions {
namespace HttpFilters {
namespace CustomHeaderInjection {

CustomHeaderInjectionFilter::CustomHeaderInjectionFilter(const ConfigSharedPtr config)
    : config_(config) {}

CustomHeaderInjectionFilter::~CustomHeaderInjectionFilter() = default;

Http::FilterHeadersStatus CustomHeaderInjectionFilter::decodeHeaders(
    Http::RequestHeaderMap& headers, bool) {
  // Inject request headers based on rules
  if (config_) {
    for (const auto& rule : config_->getRules()) {
      if (rule.inject_on_request) {
        headers.addReference(Http::LowerCaseString(rule.header_name), rule.header_value);
      }
    }
  }
  return Http::FilterHeadersStatus::Continue;
}

Http::FilterHeadersStatus CustomHeaderInjectionFilter::encodeHeaders(
    Http::ResponseHeaderMap& headers, bool) {
  // Inject response headers based on rules
  if (config_) {
    for (const auto& rule : config_->getRules()) {
      if (rule.inject_on_response) {
        headers.addReference(Http::LowerCaseString(rule.header_name), rule.header_value);
      }
    }
  }
  return Http::FilterHeadersStatus::Continue;
}

void CustomHeaderInjectionFilter::setDecoderFilterCallbacks(
    Http::StreamDecoderFilterCallbacks& callbacks) {
  decoder_callbacks_ = &callbacks;
}

void CustomHeaderInjectionFilter::setEncoderFilterCallbacks(
    Http::StreamEncoderFilterCallbacks& callbacks) {
  encoder_callbacks_ = &callbacks;
}

} // namespace CustomHeaderInjection
} // namespace HttpFilters
} // namespace Extensions
} // namespace Envoy

